import "../styles/Team.css";

export default function Team() {
  const centerMember = {
    name: "Your Name",
    role: "Founder / CEO",
    imgSrc: "/path-to-image/you.jpg",
    caption: "Visionary behind the team’s success",
  };

  const teamMembers = [
    {
      name: "John Doe",
      role: "Lead Designer",
      imgSrc: "/path-to-image/john.jpg",
    },
    {
      name: "Jane Smith",
      role: "Senior Developer",
      imgSrc: "/path-to-image/jane.jpg",
    },
    {
      name: "Emily Johnson",
      role: "Project Manager",
      imgSrc: "/path-to-image/emily.jpg",
    },
    {
      name: "Mike Brown",
      role: "UX Specialist",
      imgSrc: "/path-to-image/mike.jpg",
    },
    {
      name: "Sara Lee",
      role: "QA Engineer",
      imgSrc: "/path-to-image/sara.jpg",
    },
    {
      name: "David Kim",
      role: "DevOps Engineer",
      imgSrc: "/path-to-image/david.jpg",
    },
    {
      name: "Lily Adams",
      role: "Marketing Lead",
      imgSrc: "/path-to-image/lily.jpg",
    },
    {
      name: "Tom White",
      role: "Backend Developer",
      imgSrc: "/path-to-image/tom.jpg",
    },
    {
      name: "Rachel Green",
      role: "Content Strategist",
      imgSrc: "/path-to-image/rachel.jpg",
    },
    {
      name: "Chris Black",
      role: "Frontend Engineer",
      imgSrc: "/path-to-image/chris.jpg",
    },
  ];

  return (
    <section className="team-section">
      <h3>Meet the Team</h3>
      <div className="square-grid">
        {teamMembers.slice(0, 4).map((member, index) => (
          <div className="grid-member" key={index}>
            <img src={member.imgSrc} alt={member.name} />
            <p>{member.name}</p>
            <span>{member.role}</span>
          </div>
        ))}
        <div className="grid-center">
          <img src={centerMember.imgSrc} alt={centerMember.name} />
          <h4>{centerMember.name}</h4>
          <p className="role">{centerMember.role}</p>
        </div>
        {teamMembers.slice(4).map((member, index) => (
          <div className="grid-member" key={index + 4}>
            <img src={member.imgSrc} alt={member.name} />
            <p>{member.name}</p>
            <span>{member.role}</span>
          </div>
        ))}
      </div>
    </section>
  );
}
